    {
      "path": "src/server.js",
      "content": "const fs = require('fs');
const path = require('path');

function loadTodos(filePath) {
  try {
    return JSON.parse(fs.readFileSync(filePath, 'utf8')) || [];
  } catch (error) {
    return [];
  }
}

function saveTodos(todos, filePath) {
  fs.writeFileSync(filePath, JSON.stringify(todos, null, 2), 'utf8');
}

module.exports = function createServer(dataDir) {
  const todosFilePath = path.join(dataDir, 'todos.json');
  let todos = loadTodos(todosFilePath);

  return (req, res) => {
    const { method, url } = req;
    let body = '';

    req.on('data', chunk => {
      body += chunk.toString();
    });

    req.on('end', () => {
      if (url === '/health' && method === 'GET') {
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ ok: true }));
      } else if (url === '/openapi.json' && method === 'GET') {
        const openApiSpec = JSON.parse(fs.readFileSync('openapi.json', 'utf8'));
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify(openApiSpec));
      } else if (url === '/todos' && method === 'GET') {
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ ok: true, todos }));
      } else if (url === '/todos' && method === 'POST') {
        try {
          const newTodo = JSON.parse(body);
          if (!newTodo.title) {
            res.writeHead(400, { 'Content-Type': 'application/json' });
            return res.end(JSON.stringify({ ok: false, message: 'Title is required' }));
          }

          const todoId = Date.now().toString();
          todos.push({ id: todoId, title: newTodo.title, done: false });
          saveTodos(todos, todosFilePath);

          res.writeHead(201, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: true, todo: { id: todoId, title: newTodo.title, done: false } }));
        } catch (error) {
          res.writeHead(400, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: false, message: 'Invalid JSON' }));
        }
      } else if (url.startsWith('/todos/') && method === 'GET') {
        const todoId = url.split('/')[2];
        const todo = todos.find(t => t.id === todoId);

        if (todo) {
          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: true, todo }));
        } else {
          res.writeHead(404, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: false, message: 'Todo not found' }));
        }
      } else if (url.startsWith('/todos/') && method === 'PATCH') {
        const todoId = url.split('/')[2];
        let todoIndex = todos.findIndex(t => t.id === todoId);

        if (todoIndex !== -1) {
          try {
            const updateData = JSON.parse(body);
            if (updateData.done !== undefined) {
              todos[todoIndex] = { ...todos[todoIndex], done: updateData.done };
              saveTodos(todos, todosFilePath);

              res.writeHead(200, { 'Content-Type': 'application/json' });
              res.end(JSON.stringify({ ok: true, todo: todos[todoIndex] }));
            } else {
              res.writeHead(400, { 'Content-Type': 'application/json' });
              res.end(JSON.stringify({ ok: false, message: 'Invalid update data' }));
            }
          } catch (error) {
            res.writeHead(400, { 'Content-Type': 'application/json' });
            res.end(JSON.stringify({ ok: false, message: 'Invalid JSON' }));
          }
        } else {
          res.writeHead(404, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: false, message: 'Todo not found' }));
        }
      } else if (url.startsWith('/todos/') && method === 'DELETE') {
        const todoId = url.split('/')[2];
        let todoIndex = todos.findIndex(t => t.id === todoId);

        if (todoIndex !== -1) {
          todos.splice(todoIndex, 1);
          saveTodos(todos, todosFilePath);

          res.writeHead(200, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: true }));
        } else {
          res.writeHead(404, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ ok: false, message: 'Todo not found' }));
        }
      } else {
        res.writeHead(404, { 'Content-Type': 'text/plain' });
        res.end('Not Found');
      }
    });
  };
};"
    }
  ],
  "notes": "This is the first iteration of the API server. It includes endpoints for health check, OpenAPI specification retrieval, and CRUD operations on todos."
}
